                                    .border(1.dp, WarningHotPink.copy(alpha = 0.6f), RoundedCornerShape(4.dp))
                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                            ) {
                                Text(
                                    text = "$unindexedFilesCount NUEVOS ⚡",
